glsl3.vert:
precision highp float;
layout(std140) uniform CCGlobal {
  highp   vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_nativeSize;
  mediump vec4 cc_probeInfo;
  mediump vec4 cc_debug_view_mode;
};
layout(std140) uniform CCCamera {
  highp   mat4 cc_matView;
  highp   mat4 cc_matViewInv;
  highp   mat4 cc_matProj;
  highp   mat4 cc_matProjInv;
  highp   mat4 cc_matViewProj;
  highp   mat4 cc_matViewProjInv;
  highp   vec4 cc_cameraPos;
  mediump vec4 cc_surfaceTransform;
  mediump vec4 cc_screenScale;
  mediump vec4 cc_exposure;
  mediump vec4 cc_mainLitDir;
  mediump vec4 cc_mainLitColor;
  mediump vec4 cc_ambientSky;
  mediump vec4 cc_ambientGround;
  mediump vec4 cc_fogColor;
  mediump vec4 cc_fogBase;
  mediump vec4 cc_fogAdd;
  mediump vec4 cc_nearFar;
  mediump vec4 cc_viewPort;
};
#if USE_LOCAL
  layout(std140) uniform CCLocal {
    highp mat4 cc_matWorld;
    highp mat4 cc_matWorldIT;
    highp vec4 cc_lightingMapUVParam;
    highp vec4 cc_localShadowBias;
    highp vec4 cc_reflectionProbeData1;
    highp vec4 cc_reflectionProbeData2;
    highp vec4 cc_reflectionProbeBlendData1;
    highp vec4 cc_reflectionProbeBlendData2;
  };
#endif
in vec3 a_position;
in vec2 a_texCoord;
in vec4 a_color;
out vec4 color;
out vec2 uv0;
vec4 vert () {
  vec4 pos = vec4(a_position, 1);
  #if USE_LOCAL
    pos = cc_matWorld * pos;
  #endif
  pos = cc_matViewProj * pos;
  uv0 = a_texCoord;
  color = a_color;
  return pos;
}
void main() { gl_Position = vert(); }

glsl3.frag:
precision highp float;
vec4 CCSampleWithAlphaSeparated(sampler2D tex, vec2 uv) {
#if CC_USE_EMBEDDED_ALPHA
  return vec4(texture(tex, uv).rgb, texture(tex, uv + vec2(0.0, 0.5)).r);
#else
  return texture(tex, uv);
#endif
}
#if USE_ALPHA_TEST
  layout(std140) uniform ALPHA_TEST_DATA {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
    if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
    if (alpha < alphaThreshold) discard;
  #endif
}
in vec4 color;
in vec2 uv0;
uniform sampler2D cc_spriteTexture;
layout(std140) uniform LightningParams {
  vec4 lightningTarget;
  vec4 lightningScreen;
  vec4 lightningProgress;
  vec4 lightningSeed;
  vec4 lightningColor;
};
float hash (float n) {
  return fract(sin(n) * 43758.5453123);
}
float segmentDistance (vec2 p, vec2 a, vec2 b) {
  vec2 pa = p - a;
  vec2 ba = b - a;
  float h = clamp(dot(pa, ba) / max(dot(ba, ba), 0.0001), 0.0, 1.0);
  return length(pa - ba * h);
}
vec2 boltPoint (float t, vec2 start, vec2 target, float seed, float strength) {
  vec2 p = mix(start, target, t);
  float coarse = hash(floor(t * 8.0) + seed) - 0.5;
  float mid = hash(floor(t * 18.0) + seed * 2.7) - 0.5;
  float fine = hash(floor(t * 37.0) + seed * 5.1) - 0.5;
  float jag = (coarse * 1.85 + mid * 1.15 + fine * 0.45) * strength;
  float taper = sin(t * 3.1415926);
  float converge = 1.0 - smoothstep(0.72, 1.0, t);
  float wave = sin(t * 26.0 + seed) * 0.24 + sin(t * 57.0 + seed * 0.37) * 0.13;
  p.x += (jag + wave * strength) * taper * converge;
  return p;
}
vec4 frag () {
  vec4 tex = CCSampleWithAlphaSeparated(cc_spriteTexture, uv0) * color;
  vec2 p = gl_FragCoord.xy;
  vec2 target = lightningTarget.xy;
  vec2 start = vec2(target.x, lightningScreen.y);
  float progress = clamp(lightningProgress.x, 0.0, 1.0);
  float life = sin(progress * 3.1415926);
  float mainDist = 99999.0;
  float branchDist = 99999.0;
  vec2 prev = start;
  float segments = 22.0;
  float visibleEnd = smoothstep(0.0, 0.28, progress);
  for (float i = 1.0; i <= 22.0; i += 1.0) {
    float t = i / segments;
    vec2 next = boltPoint(t, start, target, lightningSeed.x, 118.0);
    float segmentMask = step(t, visibleEnd);
    mainDist = min(mainDist, mix(99999.0, segmentDistance(p, prev, next), segmentMask));
    float branchMask = step(0.16, t) * step(t, 0.68) * step(hash(i + lightningSeed.x + 91.0), 0.58) * segmentMask;
    vec2 dir = normalize(next - prev + vec2(0.0001, 0.0001));
    vec2 normal = vec2(-dir.y, dir.x);
    float side = hash(i + lightningSeed.x + 31.0) > 0.5 ? 1.0 : -1.0;
    vec2 branchMid = next + normal * side * (22.0 + hash(i + lightningSeed.x + 7.0) * 48.0) + dir * (6.0 + hash(i + lightningSeed.x + 11.0) * 18.0);
    vec2 branchEnd = branchMid + normal * side * (8.0 + hash(i + lightningSeed.x + 17.0) * 24.0) - dir * (4.0 + hash(i + lightningSeed.x + 23.0) * 12.0);
    branchDist = min(branchDist, mix(99999.0, segmentDistance(p, next, branchMid), branchMask));
    branchDist = min(branchDist, mix(99999.0, segmentDistance(p, branchMid, branchEnd), branchMask));
    prev = next;
  }
  float core = 1.0 - smoothstep(0.0, 2.2, mainDist);
  float glow = 1.0 - smoothstep(4.0, 24.0, mainDist);
  float branch = 1.0 - smoothstep(0.0, 1.7, branchDist);
  float branchGlow = 1.0 - smoothstep(3.0, 13.0, branchDist);
  float impactCore = 1.0 - smoothstep(0.0, 10.0, distance(p, target));
  float impact = 1.0 - smoothstep(0.0, 55.0, distance(p, target));
  float flash = smoothstep(0.02, 0.16, progress) * (1.0 - smoothstep(0.35, 1.0, progress));
  vec3 blueWhite = vec3(0.68, 0.94, 1.0);
  vec3 purpleWhite = vec3(0.82, 0.62, 1.0);
  vec3 boltColor = mix(lightningColor.rgb, blueWhite, core * 0.72);
  boltColor = mix(boltColor, purpleWhite, branch * 0.38 + branchGlow * 0.22 + glow * 0.18);
  float alpha = (core + glow * 0.42 + branch * 0.65 + branchGlow * 0.22 + impact * flash * 0.75 + impactCore * 1.25) * life * lightningColor.a;
  vec3 rgb = boltColor * (core * 2.2 + glow * 0.65 + branch * 1.45 + branchGlow * 0.35 + impact * flash * 1.4 + impactCore * 2.6) * life;
  rgb += purpleWhite * (glow * 0.28 + branchGlow * 0.25 + impact * flash * 0.22) * life;
  vec4 o = vec4(rgb, alpha * tex.a);
  ALPHA_TEST(o);
  return o;
}
layout(location = 0) out vec4 cc_FragColor;
void main() { cc_FragColor = frag(); }

